DROP TABLE IF EXISTS `tb_academic_warning`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_academic_warning` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '预警记录ID',
  `student_id` bigint NOT NULL COMMENT '学生ID，对应 tb_user.id',
  `course_id` bigint NOT NULL COMMENT '课程ID，对应 tb_course.id',
  `enrollment_id` bigint DEFAULT NULL COMMENT '选课记录ID，对应 tb_enrollment.id',
  `warning_type` tinyint NOT NULL COMMENT '预警类型：1=期中预警，2=期末预警，3=考勤预警',
  `severity` tinyint NOT NULL DEFAULT '1' COMMENT '严重程度：1=一般，2=严重，3=非常严重',
  `current_score` decimal(5,2) DEFAULT NULL COMMENT '触发预警时的成绩',
  `threshold_score` decimal(5,2) DEFAULT NULL COMMENT '触发阈值',
  `description` varchar(500) DEFAULT NULL COMMENT '预警描述',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态：0=未处理，1=已通知，2=已处理',
  `processed_by` bigint DEFAULT NULL COMMENT '处理人ID，对应 tb_user.id',
  `process_comment` varchar(500) DEFAULT NULL COMMENT '处理意见',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `processed_at` datetime DEFAULT NULL COMMENT '处理时间',
  PRIMARY KEY (`id`),
  KEY `idx_warning_student` (`student_id`),
  KEY `idx_warning_status` (`status`),
  KEY `idx_warning_created` (`created_at`),
  KEY `fk_warning_course` (`course_id`),
  KEY `fk_warning_enrollment` (`enrollment_id`),
  KEY `fk_warning_processor` (`processed_by`),
  CONSTRAINT `fk_warning_course` FOREIGN KEY (`course_id`) REFERENCES `tb_course` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_warning_enrollment` FOREIGN KEY (`enrollment_id`) REFERENCES `tb_enrollment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_warning_processor` FOREIGN KEY (`processed_by`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_warning_student` FOREIGN KEY (`student_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学业预警表';
/*!40101 SET character_set_client = @saved_cs_client */;

