DROP TABLE IF EXISTS `tb_assignment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_assignment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '作业ID',
  `course_id` bigint NOT NULL COMMENT '课程ID，对应 tb_course.id',
  `teacher_id` bigint NOT NULL COMMENT '发布教师ID，对应 tb_user.id',
  `title` varchar(100) NOT NULL COMMENT '作业标题',
  `description` text COMMENT '作业说明',
  `full_score` int NOT NULL DEFAULT '100' COMMENT '满分',
  `start_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '学生可开始作业的时间',
  `deadline` datetime NOT NULL COMMENT '截止时间',
  `allow_late_submission` tinyint NOT NULL DEFAULT '0' COMMENT '是否允许延期提交：0=不允许，1=允许',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '作业状态：0=草稿，1=已发布，2=已截止',
  `published_at` datetime DEFAULT NULL COMMENT '正式发布时间，草稿可为空',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`id`),
  KEY `idx_assignment_course` (`course_id`),
  KEY `idx_assignment_teacher` (`teacher_id`),
  KEY `idx_assignment_deadline` (`deadline`),
  CONSTRAINT `fk_assignment_course` FOREIGN KEY (`course_id`) REFERENCES `tb_course` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_assignment_teacher` FOREIGN KEY (`teacher_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2026071433 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='作业表';
/*!40101 SET character_set_client = @saved_cs_client */;

