DROP TABLE IF EXISTS `tb_assignment_attachment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_assignment_attachment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '作业附件ID',
  `assignment_id` bigint NOT NULL COMMENT '作业ID，对应 tb_assignment.id',
  `original_name` varchar(255) NOT NULL COMMENT '原始文件名',
  `stored_name` varchar(255) NOT NULL COMMENT '服务器存储文件名',
  `content_type` varchar(100) DEFAULT NULL COMMENT '文件类型',
  `file_size` bigint NOT NULL COMMENT '文件大小，字节',
  `uploaded_by` bigint NOT NULL COMMENT '上传教师ID，对应 tb_user.id',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传时间',
  PRIMARY KEY (`id`),
  KEY `idx_assignment_attachment_assignment` (`assignment_id`),
  KEY `fk_assignment_attachment_uploader` (`uploaded_by`),
  CONSTRAINT `fk_assignment_attachment_assignment` FOREIGN KEY (`assignment_id`) REFERENCES `tb_assignment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_assignment_attachment_uploader` FOREIGN KEY (`uploaded_by`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2026071403 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='教师发布的作业附件表';
/*!40101 SET character_set_client = @saved_cs_client */;

