--
-- Table structure for table `tb_course`
--

DROP TABLE IF EXISTS `tb_course`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_course` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '课程ID',
  `code` varchar(20) DEFAULT NULL,
  `teacher_id` bigint NOT NULL COMMENT '授课教师ID，对应 tb_user.id',
  `name` varchar(100) NOT NULL COMMENT '课程名称',
  `description` text COMMENT '课程简介',
  `cover_url` varchar(255) DEFAULT NULL COMMENT '课程封面地址',
  `max_students` int NOT NULL DEFAULT '100' COMMENT '最大选课人数',
  `enrolled_count` int NOT NULL DEFAULT '0' COMMENT '当前已选人数',
  `credit` decimal(4,1) DEFAULT NULL,
  `dept` varchar(50) DEFAULT NULL,
  `category` varchar(30) DEFAULT NULL,
  `tags` varchar(100) DEFAULT NULL,
  `class_count` int DEFAULT '1',
  `class_id` bigint DEFAULT NULL COMMENT '默认教学班ID，对应 tb_course_class.id',
  `academic_year` varchar(9) DEFAULT NULL COMMENT '学年，如 2025-2026',
  `semester` tinyint DEFAULT NULL COMMENT '开课学期：1=上学期，2=下学期，3=短学期',
  `total_hours` smallint DEFAULT NULL COMMENT '总学时',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '课程状态：0=下架，1=正常',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`id`),
  KEY `idx_course_teacher` (`teacher_id`),
  KEY `idx_course_status` (`status`),
  KEY `fk_course_default_class` (`class_id`),
  CONSTRAINT `fk_course_default_class` FOREIGN KEY (`class_id`) REFERENCES `tb_course_class` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_course_teacher` FOREIGN KEY (`teacher_id`) REFERENCES `tb_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=9406 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='课程表';
/*!40101 SET character_set_client = @saved_cs_client */;

