INSERT INTO `tb_course` VALUES (9101,'9101',9002,'Java Web 开发实战','围绕 Spring Boot、网关、接口联调完成在线教育系统后端开发。',NULL,60,5,3.0,'计算机科学与技术学院','必修','核心课',2,910101,'2025-2026',2,48,1,'2026-07-13 10:29:31','2026-07-21 09:53:06',0),(9102,'9102',9002,'数据库设计与 MyBatis Plus','学习核心业务表设计、实体映射、逻辑删除和常用 CRUD。',NULL,45,4,3.5,'计算机科学与技术学院','必修','核心课',3,910201,'2025-2026',2,56,1,'2026-07-13 10:29:31','2026-07-21 09:53:06',0),(9103,'9103',9003,'前端工程化与 Vue3','使用 Vue3、Vite、Pinia、Element Plus 构建管理端页面。',NULL,50,3,2.0,'软件工程系','必修','核心课',2,910301,'2025-2026',2,32,1,'2026-07-13 10:29:31','2026-07-21 09:53:06',0),(9104,'9104',9003,'旧版下架课程样例','用于验证课程下架状态过滤。',NULL,30,3,3.0,'软件工程系','必修','核心课',2,910401,'2025-2026',2,48,0,'2026-07-13 14:18:38','2026-07-21 09:53:06',0),(9105,'9105',101,'数据结构与算法','学习线性表、树、图、查找、排序及常用算法设计方法，结合复杂度分析和编程练习提升问题建模与求解能力。',NULL,100,4,4.0,'计算机科学与技术学院','必修','核心课',4,910501,'2025-2026',2,64,1,'2026-07-11 14:50:44','2026-07-22 11:41:21',0),(9106,'9106',102,'操作系统','讲解进程与线程、处理器调度、内存管理、文件系统和设备管理，理解操作系统核心机制及并发程序运行原理。',NULL,100,1,3.5,'计算机科学与技术学院','必修','核心课',3,910601,'2025-2026',2,56,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9107,'9107',102,'计算机网络','系统学习计算机网络体系结构、TCP/IP 协议、路由交换、应用层协议与网络安全基础，并通过抓包实验分析通信过程。',NULL,100,1,3.5,'计算机科学与技术学院','必修','核心课',3,910701,'2025-2026',2,56,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9108,'9108',102,'软件工程','介绍需求分析、软件设计、编码规范、测试、项目管理与持续交付，培养团队协作和完整软件生命周期实践能力。',NULL,100,1,3.0,'软件工程系','必修','核心课',3,910801,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9109,'9109',102,'编译原理','学习词法分析、语法分析、语义分析、中间代码生成与优化，理解高级语言从源代码到目标程序的转换过程。',NULL,100,0,3.0,'软件工程系','必修','专业课',2,910901,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-18 13:31:19',0),(9110,'9110',102,'Linux 系统管理','通过命令行、用户权限、进程服务、网络、存储和 Shell 脚本实践，掌握 Linux 服务器的基础配置与运维方法。',NULL,100,1,2.5,'软件工程系','必修','实践课',2,911001,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9201,'9201',103,'Python 数据分析','使用 Python、NumPy、Pandas 与可视化工具完成数据清洗、统计分析和结果展示，培养从原始数据提取信息的能力。',NULL,100,3,2.0,'软件工程系','选修','专业选修',2,920101,'2025-2026',2,32,1,'2026-07-11 14:50:44','2026-07-18 13:31:19',0),(9202,'9202',103,'Vue3 前端开发','学习 Vue 3 组合式 API、组件化、路由、状态管理和工程化工具，完成响应式前端应用的设计、开发与联调。',NULL,100,1,2.0,'软件工程系','选修','专业选修',2,920201,'2025-2026',2,32,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9203,'9203',103,'人工智能基础','介绍人工智能的基本概念、搜索、知识表示、机器学习与典型应用，通过案例建立 AI 问题建模和实现基础。',NULL,100,1,2.5,'人工智能学院','选修','AI课程',2,920301,'2025-2026',2,40,1,'2026-07-11 14:50:44','2026-07-18 13:31:19',0),(9204,'9204',104,'深度学习导论','学习神经网络、反向传播、卷积网络、循环网络和模型训练方法，使用主流框架完成基础深度学习实验。',NULL,100,2,2.5,'人工智能学院','选修','AI课程',1,920401,'2025-2026',2,40,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9205,'9205',104,'云计算与容器技术','介绍云计算架构、虚拟化、Docker、容器编排与持续部署，通过实验掌握应用容器化和云原生部署基础。',NULL,100,2,2.0,'软件工程系','选修','专业选修',2,920501,'2025-2026',2,40,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9206,'9206',104,'大数据技术基础','学习分布式存储与计算、大数据处理流程及常用生态组件，理解海量数据采集、处理、分析的基本方法。',NULL,100,2,2.5,'计算机科学与技术学院','选修','专业选修',2,920601,'2025-2026',2,40,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9301,'9301',105,'大学生心理健康教育','围绕自我认知、情绪调节、人际交往、压力管理和心理危机预防，帮助学生提升心理健康意识与自我调适能力。',NULL,100,2,2.0,'马克思主义学院','通识','通识课',5,930101,'2025-2026',2,32,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9302,'9302',105,'大学生职业发展与就业指导','通过职业认知、能力探索、简历面试和就业政策指导，帮助学生制定职业发展计划并提升求职实践能力。',NULL,100,2,1.5,'学生工作部','通识','通识课',4,930201,'2025-2026',2,24,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9303,'9303',105,'中国近现代史纲要','梳理中国近现代社会发展的历史进程和重大事件，理解中国人民选择中国共产党、马克思主义和社会主义道路的历史逻辑。',NULL,100,1,3.0,'马克思主义学院','通识','思政课',6,930301,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-18 13:31:19',0),(9304,'9304',105,'大学英语（四）','训练英语听、说、读、写、译综合能力，结合学术与职场语境提升信息理解、表达和跨文化沟通水平。',NULL,100,2,2.0,'外国语学院','通识','公共课',5,930401,'2025-2026',2,32,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9305,'9305',105,'体育（四）','通过专项运动训练提升力量、耐力、协调性与运动技能，掌握科学锻炼方法并形成健康生活习惯。',NULL,100,1,1.0,'体育学院','通识','公共课',8,930501,'2025-2026',2,32,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9401,'9401',106,'开源软件项目实践','以真实开源仓库为载体，实践 Git 协作、Issue 管理、代码评审、测试和文档编写，完成一次规范的开源贡献。',NULL,100,2,2.0,'软件工程系','个性课程','创新实践',1,940101,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9402,'9402',106,'企业级项目开发实训','按照企业研发流程开展需求分析、架构设计、协作开发、测试和部署，综合运用前后端技术完成项目交付。',NULL,100,3,3.0,'软件工程系','个性课程','实践课',1,940201,'2025-2026',2,64,1,'2026-07-11 14:50:44','2026-07-19 23:31:57',0),(9403,'9403',106,'科技创新训练','面向实际问题开展选题调研、方案设计、原型实现和成果汇报，培养创新思维、科研方法与团队实践能力。',NULL,100,2,2.0,'创新创业学院','个性课程','创新创业',2,940301,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9404,'9404',106,'ACM 程序设计竞赛训练','围绕算法与数据结构开展专题训练、模拟竞赛和代码复盘，提升程序设计速度、正确性与复杂问题求解能力。',NULL,100,1,2.0,'软件工程系','个性课程','创新实践',1,940401,'2025-2026',2,48,1,'2026-07-11 14:50:44','2026-07-19 23:20:09',0),(9405,'9405',106,'毕业设计（软件工程）','在教师指导下完成软件工程课题的需求分析、系统设计、编码测试、论文撰写与答辩，形成完整毕业成果。',NULL,100,0,8.0,'软件工程系','个性课程','毕业实践',6,940501,'2025-2026',2,128,1,'2026-07-11 14:50:44','2026-07-18 13:31:19',0);
