--
-- Table structure for table `tb_course_class`
--

DROP TABLE IF EXISTS `tb_course_class`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_course_class` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '教学班ID',
  `course_id` bigint NOT NULL COMMENT '课程ID，对应 tb_course.id',
  `teacher_id` bigint NOT NULL COMMENT '授课教师ID，对应 tb_user.id',
  `name` varchar(100) NOT NULL COMMENT '教学班名称，如 计科2301班',
  `max_students` int NOT NULL DEFAULT '60' COMMENT '班级容量',
  `enrolled_count` int NOT NULL DEFAULT '0' COMMENT '当前已选人数',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：0=停开，1=开课',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`id`),
  KEY `idx_course_class_course` (`course_id`),
  KEY `idx_course_class_teacher` (`teacher_id`),
  CONSTRAINT `fk_course_class_course` FOREIGN KEY (`course_id`) REFERENCES `tb_course` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_course_class_teacher` FOREIGN KEY (`teacher_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=940542 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='教学班表';
/*!40101 SET character_set_client = @saved_cs_client */;

