--
-- Table structure for table `tb_course_schedule`
--

DROP TABLE IF EXISTS `tb_course_schedule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_course_schedule` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '排课ID',
  `class_id` bigint NOT NULL COMMENT '教学班ID，对应 tb_course_class.id',
  `day_of_week` tinyint NOT NULL COMMENT '星期：1=周一~7=周日',
  `start_period` tinyint NOT NULL COMMENT '开始节次',
  `end_period` tinyint NOT NULL COMMENT '结束节次',
  `start_week` tinyint NOT NULL COMMENT '起始教学周',
  `end_week` tinyint NOT NULL COMMENT '结束教学周',
  `week_type` tinyint NOT NULL DEFAULT '0' COMMENT '周类型：0=全周，1=单周，2=双周',
  `location` varchar(100) DEFAULT NULL COMMENT '上课地点',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_schedule_class` (`class_id`),
  KEY `idx_schedule_weekday` (`day_of_week`,`start_period`),
  CONSTRAINT `fk_schedule_class` FOREIGN KEY (`class_id`) REFERENCES `tb_course_class` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=338 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='教学班排课表';
/*!40101 SET character_set_client = @saved_cs_client */;

