--
-- Table structure for table `tb_enrollment`
--

DROP TABLE IF EXISTS `tb_enrollment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_enrollment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '选课记录ID',
  `class_id` bigint NOT NULL COMMENT '教学班ID',
  `course_id` bigint NOT NULL COMMENT '课程ID，对应 tb_course.id',
  `student_id` bigint NOT NULL COMMENT '学生ID，对应 tb_user.id',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '0=PENDING, 1=APPROVED, 2=DROPPED, 4=REJECTED',
  `final_score` decimal(5,2) DEFAULT NULL COMMENT '最终成绩',
  `grade_letter` varchar(2) DEFAULT NULL COMMENT '等第：A/B/C/D/F',
  `passed` tinyint DEFAULT NULL COMMENT '是否通过：0=未通过，1=通过',
  `apply_reason` varchar(255) DEFAULT NULL COMMENT '选课申请说明',
  `review_comment` varchar(255) DEFAULT NULL COMMENT '审核意见',
  `applied_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `reviewed_at` datetime DEFAULT NULL COMMENT '审核时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_enrollment_class_student` (`class_id`,`student_id`),
  KEY `idx_enrollment_student` (`student_id`),
  KEY `idx_enrollment_class_status` (`class_id`,`status`),
  CONSTRAINT `fk_enrollment_class` FOREIGN KEY (`class_id`) REFERENCES `tb_course_class` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_enrollment_student` FOREIGN KEY (`student_id`) REFERENCES `tb_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=9397 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学生选课表';
/*!40101 SET character_set_client = @saved_cs_client */;

