--
-- Table structure for table `tb_exam`
--

DROP TABLE IF EXISTS `tb_exam`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_exam` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '考试ID',
  `course_id` bigint NOT NULL COMMENT '课程ID，对应 tb_course.id',
  `teacher_id` bigint NOT NULL COMMENT '发布教师ID，对应 tb_user.id',
  `title` varchar(100) NOT NULL COMMENT '考试标题',
  `description` text COMMENT '考试说明',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `full_score` int NOT NULL DEFAULT '100' COMMENT '满分',
  `duration` int NOT NULL DEFAULT '60' COMMENT '考试时长（分钟）',
  `max_attempts` int NOT NULL DEFAULT '1' COMMENT '允许提交次数',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '考试状态：0=草稿，1=已发布，2=已结束',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`id`),
  KEY `idx_exam_course` (`course_id`),
  KEY `idx_exam_teacher` (`teacher_id`),
  KEY `idx_exam_time` (`start_time`,`end_time`),
  CONSTRAINT `fk_exam_course` FOREIGN KEY (`course_id`) REFERENCES `tb_course` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_exam_teacher` FOREIGN KEY (`teacher_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9513 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='考试表';
/*!40101 SET character_set_client = @saved_cs_client */;

