  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '考试参与记录ID',
  `exam_id` bigint NOT NULL COMMENT '考试ID，对应 tb_exam.id',
  `student_id` bigint NOT NULL COMMENT '学生ID，对应 tb_user.id',
  `answer_content` longtext COMMENT '考试作答内容，后续可改为结构化答题明细',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '参与状态：0=进行中，1=已提交，2=已批改',
  `score` int DEFAULT NULL COMMENT '考试得分',
  `teacher_comment` text COMMENT '教师评语',
  `started_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '开始考试时间',
  `submitted_at` datetime DEFAULT NULL COMMENT '交卷时间',
  `graded_at` datetime DEFAULT NULL COMMENT '批改时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_exam_attempt_exam_student` (`exam_id`,`student_id`),
  KEY `idx_exam_attempt_student` (`student_id`),
  KEY `idx_exam_attempt_status` (`exam_id`,`status`),
  CONSTRAINT `fk_exam_attempt_exam` FOREIGN KEY (`exam_id`) REFERENCES `tb_exam` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_exam_attempt_student` FOREIGN KEY (`student_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学生考试参与记录表';
