CREATE TABLE `tb_question` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '题目ID',
  `exam_id` bigint NOT NULL COMMENT '考试ID，对应 tb_exam.id',
  `type` tinyint NOT NULL COMMENT '题型：0=选择题，1=填空题',
  `title` text NOT NULL COMMENT '题目内容',
  `options` text COMMENT '选择题选项，JSON 数组',
  `answer` text COMMENT '正确答案',
  `score` int NOT NULL DEFAULT '10' COMMENT '题目分值',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '题目顺序',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_question_exam_sort` (`exam_id`,`sort_order`),
  CONSTRAINT `fk_question_exam` FOREIGN KEY (`exam_id`) REFERENCES `tb_exam` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=65 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='考试题目表';
