INSERT INTO `tb_question` VALUES (1,1,0,'Spring Boot 中，以下哪个注解用于启动自动配置？','[\"@EnableAutoConfiguration\",\"@SpringBootApplication\",\"@Configuration\",\"@ComponentScan\"]','B',10,1,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(2,1,0,'HTTP 状态码 401 表示什么？','[\"服务器内部错误\",\"资源未找到\",\"未授权（需要身份验证）\",\"请求超时\"]','C',10,2,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(3,1,0,'以下哪个是 MyBatis Plus 的核心功能？','[\"自动建表\",\"代码生成器\",\"分布式事务\",\"服务网格\"]','B',10,3,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(4,1,0,'JWT 中 Token 通常存放在 HTTP 请求的哪个头部？','[\"Authorization\",\"Content-Type\",\"Accept\",\"Cookie\"]','A',10,4,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(5,1,1,'Spring Boot 默认内嵌的 Web 服务器是 ______。',NULL,'Tomcat',10,5,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(6,1,1,'MyBatis Plus 中，逻辑删除的全局配置属性是 ______。',NULL,'logic-delete-field',10,6,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(7,2,0,'数据库设计中，以下哪个是逻辑设计的产物？','[\"E-R图\",\"关系模式\",\"物理存储结构\",\"索引文件\"]','B',20,1,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(8,2,0,'MySQL 中，以下哪个存储引擎支持事务？','[\"MyISAM\",\"InnoDB\",\"Memory\",\"Archive\"]','B',20,2,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(9,2,0,'以下哪个是索引的类型？','[\"B+树索引\",\"链表索引\",\"栈索引\",\"队列索引\"]','A',20,3,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(10,2,1,'数据库事务的四个特性简称 ______。',NULL,'ACID',20,4,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(11,2,1,'MyBatis Plus 中，逻辑删除的字段值 1 表示 ______。',NULL,'已删除',20,5,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(12,3,0,'MyBatis Plus 中，以下哪个注解用于标识主键？','[\"@TableId\",\"@TableField\",\"@TableName\",\"@Key\"]','A',20,1,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(13,3,0,'BaseMapper 接口中，用于根据 ID 查询的方法是？','[\"selectOne\",\"selectById\",\"getById\",\"findById\"]','B',20,2,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(14,3,0,'MyBatis Plus 的条件构造器类是？','[\"QueryWrapper\",\"ConditionBuilder\",\"SqlBuilder\",\"CriteriaQuery\"]','A',20,3,'2026-07-19 23:13:43','2026-07-19 23:13:43'),(15,3,0,'以下哪个 MyBatis Plus 功能可以实现自动填充时间字段？','[\"MetaObjectHandler\",\"TimeHandler\",\"