DROP TABLE IF EXISTS `tb_student_grade`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_student_grade` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '学生成绩明细ID',
  `enrollment_id` bigint NOT NULL COMMENT '选课记录ID，对应 tb_enrollment.id',
  `component_id` bigint NOT NULL COMMENT '成绩组成项ID，对应 tb_grade_component.id',
  `score` decimal(6,2) DEFAULT NULL COMMENT '得分',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_grade` (`enrollment_id`,`component_id`),
  KEY `idx_student_grade_enrollment` (`enrollment_id`),
  KEY `idx_student_grade_component` (`component_id`),
  CONSTRAINT `fk_student_grade_component` FOREIGN KEY (`component_id`) REFERENCES `tb_grade_component` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_student_grade_enrollment` FOREIGN KEY (`enrollment_id`) REFERENCES `tb_enrollment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学生成绩明细表';
