DROP TABLE IF EXISTS `tb_student_profile`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_student_profile` (
  `user_id` bigint NOT NULL COMMENT '用户ID，对应 tb_user.id',
  `student_no` varchar(32) NOT NULL COMMENT '学号',
  `real_name` varchar(50) NOT NULL COMMENT '学生姓名',
  `college` varchar(100) DEFAULT NULL COMMENT '学院',
  `major` varchar(100) DEFAULT NULL COMMENT '专业',
  `class_name` varchar(100) DEFAULT NULL COMMENT '班级',
  `grade` varchar(20) DEFAULT NULL COMMENT '年级',
  `enrollment_year` smallint DEFAULT NULL COMMENT '入学年份',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除：0=正常，1=删除',
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `uk_student_profile_student_no` (`student_no`),
  CONSTRAINT `fk_student_profile_user` FOREIGN KEY (`user_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学生档案表';
