DROP TABLE IF EXISTS `tb_submission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_submission` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '作业提交ID',
  `assignment_id` bigint NOT NULL COMMENT '作业ID，对应 tb_assignment.id',
  `student_id` bigint NOT NULL COMMENT '学生ID，对应 tb_user.id',
  `content` text NOT NULL COMMENT '提交内容',
  `attachment_url` varchar(255) DEFAULT NULL COMMENT '附件地址',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '提交状态：0=暂存，1=已提交，2=已撤回',
  `grading_status` tinyint NOT NULL DEFAULT '0' COMMENT '批改状态：0=待批改，1=已批改',
  `score` int DEFAULT NULL COMMENT '得分',
  `teacher_comment` text COMMENT '教师评语',
  `ai_comment` text COMMENT 'AI辅助评语',
  `submitted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '提交时间',
  `graded_at` datetime DEFAULT NULL COMMENT '批改时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_submission_assignment_student` (`assignment_id`,`student_id`),
  KEY `idx_submission_student` (`student_id`),
  KEY `idx_submission_score` (`score`),
  CONSTRAINT `fk_submission_assignment` FOREIGN KEY (`assignment_id`) REFERENCES `tb_assignment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_submission_student` FOREIGN KEY (`student_id`) REFERENCES `tb_user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9417 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='作业提交表';
/*!40101 SET character_set_client = @saved_cs_client */;

